/* ── Related Posts Section ── */

.rp-section {
    margin-top: 2.5rem;
    padding-top: 1.5rem;
    border-top: 1px solid var(--border-light);
}

.rp-heading {
    font-family: var(--font-serif);
    font-size: 0.95rem;
    font-weight: 500;
    color: var(--text-secondary);
    letter-spacing: 0.01em;
    margin: 0 0 1rem 0;
}

/* ── Card Grid ── */

.rp-grid {
    display: flex;
    flex-direction: column;
    gap: 0.625rem;
}

/* ── Card ── */

.rp-card {
    display: flex;
    align-items: stretch;
    border-radius: 10px;
    background: var(--bg-secondary);
    border: 1px solid var(--border-card);
    cursor: pointer;
    overflow: hidden;
    transition: background 0.2s ease, border-color 0.2s ease, box-shadow 0.2s ease;
}

.rp-card:hover {
    background: var(--bg-hover);
    border-color: var(--border-light);
    box-shadow: var(--shadow-card-sm);
}

/* ── Accent Line ── */

.rp-card-accent {
    width: 3px;
    flex-shrink: 0;
    background: var(--accent-purple);
    border-radius: 3px 0 0 3px;
    transition: opacity 0.3s ease;
}

/* ── Card Content ── */

.rp-card-content {
    flex: 1;
    padding: 0.75rem 0.875rem;
    min-width: 0;
}

.rp-card-title {
    font-family: var(--font-serif);
    font-size: 0.875rem;
    font-weight: 500;
    color: var(--text-primary);
    margin: 0 0 0.375rem 0;
    line-height: 1.35;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
}

.rp-card-meta {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 0.5rem;
}

.rp-card-author {
    display: flex;
    align-items: center;
    gap: 0.375rem;
    min-width: 0;
}

.rp-card-avatar {
    width: 20px;
    height: 20px;
    border-radius: 50%;
    object-fit: cover;
    flex-shrink: 0;
}

.rp-card-avatar-placeholder {
    background: var(--bg-hover);
    border: 1px solid var(--border-light);
}

.rp-card-name {
    font-size: 0.75rem;
    color: var(--text-secondary);
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    max-width: 140px;
}

.rp-card-date {
    font-size: 0.7rem;
    color: var(--text-muted);
    white-space: nowrap;
    flex-shrink: 0;
}

/* ── Skeleton Loading ── */

.rp-skeleton-container {
    display: flex;
    flex-direction: column;
    gap: 0.625rem;
}

.rp-skeleton-card {
    display: flex;
    align-items: stretch;
    border-radius: 10px;
    background: var(--bg-secondary);
    border: 1px solid var(--border-card);
    overflow: hidden;
    height: 62px;
}

.rp-skeleton-accent {
    width: 3px;
    flex-shrink: 0;
    background: var(--bg-hover);
    animation: rp-shimmer 1.5s ease-in-out infinite;
}

.rp-skeleton-content {
    flex: 1;
    padding: 0.75rem 0.875rem;
    display: flex;
    flex-direction: column;
    justify-content: center;
    gap: 0.5rem;
}

.rp-skeleton-title {
    height: 12px;
    width: 65%;
    border-radius: 4px;
    background: var(--bg-hover);
    animation: rp-shimmer 1.5s ease-in-out infinite;
    animation-delay: 0.1s;
}

.rp-skeleton-meta {
    display: flex;
    align-items: center;
    gap: 0.375rem;
}

.rp-skeleton-avatar {
    width: 20px;
    height: 20px;
    border-radius: 50%;
    background: var(--bg-hover);
    animation: rp-shimmer 1.5s ease-in-out infinite;
    animation-delay: 0.2s;
}

.rp-skeleton-name {
    height: 10px;
    width: 80px;
    border-radius: 4px;
    background: var(--bg-hover);
    animation: rp-shimmer 1.5s ease-in-out infinite;
    animation-delay: 0.3s;
}

@keyframes rp-shimmer {
    0%, 100% { opacity: 0.4; }
    50% { opacity: 0.8; }
}

/* ── Responsive ── */

@media (max-width: 480px) {
    .rp-section {
        margin-top: 2rem;
        padding-top: 1.25rem;
    }

    .rp-card-name {
        max-width: 100px;
    }
}

