 30→
 31→const normalizeInteractionFlag = (value) => {
 32→    if(typeof value === 'boolean') return value;
 33→    if(typeof value === 'string'){
 34→        const normalized = value.trim().toLowerCase();
 35→        if(normalized === 'true') return true;
 36→        if(normalized === 'false') return false;
 37→    }
 38→    if(typeof value === 'number'){
 39→        return value === 1;
 40→    }
 41→    return Boolean(value);
 42→};
 43→
 44→const normalizeCount = (value) => {
 45→    const number = Number(value);
 46→    if(!Number.isFinite(number) || number < 0){
 47→        return 0;
 48→    }
 49→    return number;
 50→};
 51→
 52→const getNextToggleCount = (isActive, currentCount) => {
 53→    return isActive
 54→        ? Math.max(0, currentCount - 1)
 55→        : currentCount + 1;
 56→};
 57→
 58→const ContentView = () => {
 59→    const navigate = useNavigate();
 60→    const [showBackButton, setShowBackButton] = useState(true);
 61→    const { session, user, openAuthModal } = useAuth();
 62→
 63→    const timeOutRef = useRef();
