 71→    const [isBookmarked, setIsBookmarked] = useState(false);
 72→    const [bookmarkCounts, setBookmarkCounts] = useState(0);
 73→
 74→    const [bookmarkedMessage, setBookmarkedMessage] = useState('');
 75→    const [showRepostModal, setShowRepostModal] = useState(false);
