 92→        }
 93→    }
 94→
 95→    const location = useLocation();
 96→    const { journalId } = useParams();
 97→    const statePostData = location.state;
 98→    const shouldFetchPost = !!journalId && (!statePostData || !statePostData?.postType);
 99→
100→    const { data: fetchedJournalData, isLoading: isLoadingJournalById } = useQuery({
101→        queryKey: ['journalById', journalId, user?.userData?.[0]?.id],
102→        queryFn: ({ queryKey }) => getJournalById(queryKey[1], queryKey[2]),
103→        enabled: shouldFetchPost,
104→        staleTime: 1000 * 60 * 5,
105→        refetchOnWindowFocus: false,
106→    });
107→
108→    const postData = useMemo(() => {
109→        const journal = fetchedJournalData?.journal;
110→        if(journal){
111→            const postType = journal?.post_type || 'text';
112→            const parsedContent = ParseContent(journal?.content);
113→            const canvasDoc = postType === 'canvas' ? parseCanvasDoc(journal?.canvas_doc) : null;
114→            const wholeText = postType === 'canvas'
115→                ? getCanvasWholeText(canvasDoc)
116→                : (parsedContent?.wholeText || '');
117→
118→            return {
