124→                userId: journal?.users?.id || journal?.user_id,
125→                name: journal?.users?.name,
126→                avatar: journal?.users?.image_url,
127→                created_at: journal?.created_at,
128→                journalId: journal?.id,
129→                isLiked: journal?.has_liked,
130→                commentsCount: journal?.comment_count?.[0]?.count || 0,
131→                isBookmarked: journal?.has_bookmarked,
132→                likesCount: journal?.like_count?.[0]?.count || 0,
133→                bookmarksCount: journal?.bookmark_count?.[0]?.count || 0,
134→                badge: journal?.users?.badge,
135→                isRepost: journal?.is_repost === true,
136→                repostCaption: journal?.repost_caption || '',
137→                repostSource: journal?.repost_source || null
138→            };
139→        }
140→
141→        if(!statePostData){
142→            return null;
143→        }
144→
145→        const inferredPostType = statePostData?.postType || (statePostData?.canvasDoc ? 'canvas' : 'text');
146→        const parsedContent = ParseContent(statePostData?.content);
