 15→function RelatedPostCard({ post, index }) {
 16→    const navigate = useNavigate();
 17→
 18→    const handleClick = () => {
 19→        navigate(`/home/post/${post.id}`);
 20→    };
 21→
 22→    const title = post.title || 'Untitled';
 23→
 24→    // Map similarity to accent opacity (higher = brighter accent line)
 25→    const accentOpacity = Math.min(1, Math.max(0.3, (post.semantic_similarity - 0.25) / 0.5));
 26→
 27→    return (
 28→        <motion.div
 29→            className="rp-card"
 30→            onClick={handleClick}
 31→            initial={{ opacity: 0, y: 12 }}
 32→            animate={{ opacity: 1, y: 0 }}
 33→            transition={{
 34→                duration: 0.35,
 35→                delay: index * 0.06,
 36→                ease: [0.25, 0.46, 0.45, 0.94],
 37→            }}
 38→        >
 39→            <div
 40→                className="rp-card-accent"
 41→                style={{ opacity: accentOpacity }}
 42→            />
 43→            <div className="rp-card-content">
 44→                <h4 className="rp-card-title">{title}</h4>
 45→                <div className="rp-card-meta">
 46→                    <div className="rp-card-author">
 47→                        {post.user_image_url ? (
 48→                            <img
 49→                                src={post.user_image_url}
 50→                                alt=""
 51→                                className="rp-card-avatar"
 52→                            />
 53→                        ) : (
 54→                            <div className="rp-card-avatar rp-card-avatar-placeholder" />
 55→                        )}
 56→                        <span className="rp-card-name">
 57→                            {post.user_name || 'Anonymous'}
 58→                        </span>
 59→                        {post.user_badge && (
 60→                            <VerifiedBadge badge={post.user_badge} size={12} />
 61→                        )}
 62→                    </div>
 63→                    <span className="rp-card-date">
 64→                        {formatPostDate(post.created_at)}
 65→                    </span>
 66→                </div>
 67→            </div>
 68→        </motion.div>
 69→    );
 70→}
