 91→export default function RelatedPosts({ journalId }) {
 92→    const { data, isLoading } = useQuery({
 93→        queryKey: ['relatedPosts', journalId],
 94→        queryFn: () => getRelatedPosts(journalId),
 95→        enabled: !!journalId,
 96→        staleTime: 10 * 60 * 1000,
 97→        retry: false,
 98→    });
 99→
100→    if (isLoading) {
101→        return (
102→            <section className="rp-section">
103→                <RelatedPostsSkeleton />
104→            </section>
105→        );
106→    }
107→
108→    // Don't render anything if no confidence or no posts
109→    if (!data || data.confidence === 'none' || !data.posts?.length) {
110→        return null;
111→    }
112→
113→    const label = CONFIDENCE_LABELS[data.confidence];
114→    if (!label) return null;
115→
116→    return (
117→        <section className="rp-section">
118→            <h3 className="rp-heading">{label}</h3>
119→            <div className="rp-grid">
120→                {data.posts.map((post, index) => (
121→                    <RelatedPostCard
122→                        key={post.id}
123→                        post={post}
124→                        index={index}
125→                    />
126→                ))}
127→            </div>
128→        </section>
129→    );
130→}
